.message-input-container {
    display: flex;
    gap: 8px;
    padding: 12px 16px;
    border-top: 1px solid #e3e5e8;
    background: #fff;
    align-items: flex-end;
}

.message-input-container textarea {
    flex: 1;
    resize: none;
    border: 1px solid #e3e5e8;
    border-radius: 8px;
    padding: 10px 12px;
    font-size: 0.9rem;
    font-family: inherit;
    line-height: 1.4;
    outline: none;
    transition: border-color 0.15s;
    background: #f9fafb;
}

.message-input-container textarea:focus {
    border-color: #5865f2;
    background: #fff;
}

.send-btn {
    padding: 8px 20px;
    background-color: #5865f2;
    color: #fff;
    border: none;
    border-radius: 8px;
    font-size: 0.88rem;
    font-weight: 600;
    cursor: pointer;
    transition: background-color 0.15s;
    white-space: nowrap;
    height: fit-content;
}

.send-btn:hover:not(:disabled) {
    background-color: #4752c4;
}

.send-btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

