arguments.file_text:
@using sv_1996a65132ca4c368a6f14a0fbd67a49.Services

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h3>Channels</h3>
    </div>
    <div class="channel-list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == SelectedChannelId"
                         OnClick="() => OnChannelSelected.InvokeAsync(channel.Id)" />
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int? SelectedChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }
}

.channel-sidebar {
    display: flex;
    flex-direction: column;
    height: 100%;
    background-color: #2b2d31;
    color: #dcddde;
    overflow: hidden;
}

.sidebar-header {
    padding: 14px 16px;
    border-bottom: 1px solid rgba(255, 255, 255, 0.06);
    flex-shrink: 0;
}

.sidebar-header h3 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
    color: #fff;
    text-transform: uppercase;
    letter-spacing: 0.04em;
}

.channel-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

@using sv_1996a65132ca4c368a6f14a0fbd67a49.Services

<div class="message-area">
    @if (Channel is not null)
    {
        <div class="area-header">
            <div class="header-title"># @Channel.Name</div>
            <div class="header-description">@Channel.Description</div>
        </div>

        <div class="message-list">
            @if (IsLoadingMore)
            {
                <div class="loading-indicator">Loading older messages…</div>
            }
            else if (HasMoreMessages)
            {
                <button class="load-more-btn" @onclick="OnLoadMore">
                    ↑ Load older messages
                </button>
            }

            @foreach (var message in Messages)
            {
                <MessageItem Message="message"
                             ThreadSummary="GetThreadSummary(message.Id)"
                             OnReply="() => OnOpenThread.InvokeAsync(message.Id)"
                             OnOpenThread="() => OnOpenThread.InvokeAsync(message.Id)"
                             OnReact="(emoji) => OnReact.InvokeAsync((message.Id, emoji))" />
            }
        </div>

        <MessageInput Placeholder="@($"Message #{Channel.Name}")"
                      ButtonText="Send"
                      OnSubmit="OnSendMessage" />
    }
    else
    {
        <div class="no-channel">
            <div class="no-channel-icon">💬</div>
            <p>Select a channel to start chatting</p>
        </div>
    }
</div>

@code {
    [Parameter] public Channel? Channel { get; set; }
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = new();
    [Parameter] public bool HasMoreMessages { get; set; }
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }

    private ThreadSummary? GetThreadSummary(int messageId)
    {
        ThreadSummaries.TryGetValue(messageId, out var summary);
        return summary;
    }
}

.message-area {
    display: flex;
    flex-direction: column;
    height: 100%;
    background-color: #fff;
    overflow: hidden;
}

.area-header {
    padding: 12px 16px;
    border-bottom: 1px solid #e3e5e8;
    flex-shrink: 0;
    background: #fff;
}

.header-title {
    font-size: 1.1rem;
    font-weight: 700;
    color: #2e3338;
}

.header-description {
    font-size: 0.82rem;
    color: #72767d;
    margin-top: 2px;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
    display: flex;
    flex-direction: column;
}

.loading-indicator {
    text-align: center;
    padding: 12px;
    color: #72767d;
    font-size: 0.85rem;
}

.load-more-btn {
    align-self: center;
    margin: 8px 0;
