toolArgs.file_text:
@using sv_1996a65132ca4c368a6f14a0fbd67a49.Services

<div class="thread-panel">
    <div class="thread-header">
        <h3>Thread</h3>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root">
            <MessageItem Message="RootMessage"
                         OnReact="(emoji) => OnReact.InvokeAsync((RootMessage.Id, emoji))" />
        </div>

        <div class="thread-divider">
            <span>@ThreadMessages.Count @(ThreadMessages.Count == 1 ? "reply" : "replies")</span>
        </div>

        <div class="thread-messages">
            @foreach (var message in ThreadMessages)
            {
                <MessageItem Message="message"
                             OnReact="(emoji) => OnReact.InvokeAsync((message.Id, emoji))" />
            }
        </div>

        <MessageInput Placeholder="Reply in thread…"
                      ButtonText="Reply"
                      OnSubmit="OnSendReply" />
    }
</div>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> ThreadMessages { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
}

.thread-panel {
    display: flex;
    flex-direction: column;
    height: 100%;
    background-color: #fff;
    overflow: hidden;
}

.thread-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 12px 16px;
    border-bottom: 1px solid #e3e5e8;
    flex-shrink: 0;
}

.thread-header h3 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
    color: #2e3338;
}

.close-btn {
    background: none;
    border: none;
    font-size: 1.1rem;
    color: #72767d;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
    line-height: 1;
}

.close-btn:hover {
    background: #f2f3f5;
    color: #2e3338;
}

.thread-root {
    padding: 8px 0;
    border-bottom: 1px solid #e3e5e8;
    background: #f9fafb;
    flex-shrink: 0;
}

.thread-divider {
    display: flex;
    align-items: center;
    padding: 8px 16px;
    flex-shrink: 0;
}

.thread-divider::before,
.thread-divider::after {
    content: "";
    flex: 1;
    height: 1px;
    background: #e3e5e8;
}

.thread-divider span {
    padding: 0 12px;
    font-size: 0.78rem;
    color: #72767d;
    font-weight: 600;
    white-space: nowrap;
}

.thread-messages {
    flex: 1;
    overflow-y: auto;
    padding: 4px 0;
}

