arguments.file_text:
@page "/chat"
@using sv_1996a65132ca4c368a6f14a0fbd67a49.Services
@using sv_1996a65132ca4c368a6f14a0fbd67a49.Components.Chat
@inject IChatService ChatService
@rendermode InteractiveServer

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <div class="sidebar-column">
        <ChannelSidebar Channels="channels"
                        SelectedChannelId="selectedChannel?.Id"
                        OnChannelSelected="SelectChannel" />
    </div>

    <div class="main-column @(isThreadOpen ? "with-thread" : "")">
        <MessageArea Channel="selectedChannel"
                     Messages="displayMessages"
                     ThreadSummaries="threadSummaries"
                     HasMoreMessages="hasMoreMessages"
                     IsLoadingMore="isLoadingMore"
                     OnOpenThread="OpenThread"
                     OnSendMessage="SendMessage"
                     OnReact="HandleReaction"
                     OnLoadMore="LoadMoreMessages" />
    </div>

    @if (isThreadOpen)
    {
        <div class="thread-column">
            <ThreadPanel RootMessage="threadRootMessage"
                         ThreadMessages="threadMessages"
                         OnClose="CloseThread"
                         OnSendReply="SendThreadReply"
                         OnReact="HandleReaction" />
        </div>
    }
</div>

@code {
    private List<Channel> channels = [];
    private Channel? selectedChannel;
    private List<Message> allMessages = [];
    private List<Message> displayMessages = [];
    private Dictionary<int, ThreadSummary> threadSummaries = new();
    private bool hasMoreMessages = true;
    private bool isLoadingMore;

    private bool isThreadOpen;
    private int? activeThreadRootId;
    private Message? threadRootMessage;
    private List<Message> threadMessages = [];

    private const int PageSize = 50;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        selectedChannel = channels.Find(c => c.Id == channelId);
        if (selectedChannel is null) return;

        CloseThread();
        allMessages = [];
        hasMoreMessages = true;
        threadSummaries = new();

        var loaded = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        allMessages = loaded;
        hasMoreMessages = loaded.Count == PageSize;
        RebuildDisplayState();

        await ChatService.MarkChannelReadAsync(channelId);

        var idx = channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            channels[idx] = selectedChannel with { UnreadCount = 0 };
            selectedChannel = channels[idx];
        }
    }

    private async Task LoadMoreMessages()
    {
        if (selectedChannel is null || isLoadingMore || !hasMoreMessages) return;

        isLoadingMore = true;
        var older = await ChatService.GetMessagesAsync(selectedChannel.Id, allMessages.Count, PageSize);
        allMessages.InsertRange(0, older);
        hasMoreMessages = older.Count == PageSize;
        isLoadingMore = false;
        RebuildDisplayState();
    }

    private async Task SendMessage(string content)
    {
        if (selectedChannel is null) return;
        var message = await ChatService.SendMessageAsync(selectedChannel.Id, content, null);
        allMessages.Add(message);
        RebuildDisplayState();
    }

    private async Task OpenThread(int messageId)
    {
        activeThreadRootId = messageId;
        threadRootMessage = allMessages.Find(m => m.Id == messageId);
        isThreadOpen = true;

        var thread = await ChatService.GetThreadAsync(messageId);
        threadMessages = thread.Where(m => m.Id != messageId).ToList();
    }

    private void CloseThread()
    {
        isThreadOpen = false;
        activeThreadRootId = null;
        threadRootMessage = null;
        threadMessages = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (selectedChannel is null || activeThreadRootId is null) return;

        var reply = await ChatService.SendMessageAsync(selectedChannel.Id, content, activeThreadRootId);
        threadMessages.Add(reply);

        threadSummaries[activeThreadRootId.Value] = new ThreadSummary(
            activeThreadRootId.Value,
            threadMessages.Count,
            reply.SentAt);
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        ApplyReactionLocally(allMessages, args.MessageId, args.Emoji);
        ApplyReactionLocally(threadMessages, args.MessageId, args.Emoji);
        RebuildDisplayState();
    }

    private static void ApplyReactionLocally(List<Message> messages, int messageId, string emoji)
    {
        var idx = messages.FindIndex(m => m.Id == messageId);
        if (idx < 0) return;

        var msg = messages[idx];
        var reactions = msg.Reactions.ToList();
        var existing = reactions.FindIndex(r => r.Emoji == emoji);
        if (existing >= 0)
        {
            var r = reactions[existing];
            reactions[existing] = r with { Users = [.. r.Users, "You"] };
        }
        else
        {
            reactions.Add(new Reaction(emoji, ["You"]));
        }
        messages[idx] = msg with { Reactions = reactions };
    }

    private void RebuildDisplayState()
    {
        // Show only top-level messages in the main area
        displayMessages = allMessages.Where(m => m.ReplyToId is null).ToList();

        // Build thread summaries from reply messages
        threadSummaries = allMessages
            .Where(m => m.ReplyToId.HasValue)
            .GroupBy(m => m.ReplyToId!.Value)
            .ToDictionary(
                g => g.Key,
                g => new ThreadSummary(g.Key, g.Count(), g.Max(m => m.SentAt)));
    }
}

::deep .chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
}

.sidebar-column {
    width: 20%;
    min-width: 200px;
    max-width: 280px;
    flex-shrink: 0;
    border-right: 1px solid #1e1f22;
}

.main-column {
    flex: 1;
    min-width: 0;
    display: flex;
    flex-direction: column;
    transition: flex 0.2s ease;
}

.main-column.with-thread {
    flex: 55;
}

.thread-column {
    width: 25%;
    min-width: 280px;
    max-width: 420px;
    flex-shrink: 0;
    border-left: 1px solid #e3e5e8;
}

